import{_ as e,c as t,o as a,f as i}from"./chunks/framework.BOAZPCR7.js";const f=JSON.parse('{"title":"Complete definition of how mutations affect antibodies used to prevent RSV","description":"","frontmatter":{"layout":"paper","title":"Complete definition of how mutations affect antibodies used to prevent RSV","date":"2026-02-12","authors":["Cassandra AL Simonich","Teagan E McMahon","Lucas Kampman","Helen Y Chu","Jesse D Bloom"],"journal":"bioRxiv","doi":"10.64898/2026.02.12.705519","link":"https://doi.org/10.64898/2026.02.12.705519","image":"/assets/papers/2026_simonich_dms.png","keywords":["RSV","Deep mutational scanning","Pseudovirus"],"selected":true,"head":[["link",{"rel":"canonical","href":"https://jbloomlab.org/papers/2026_simonich_dms.html"}]]},"headers":[],"relativePath":"papers/2026_simonich_dms.md","filePath":"papers/2026_simonich_dms.md"}'),n={name:"papers/2026_simonich_dms.md"},s=i('<h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>New antibodies targeting the F protein of respiratory syncytial virus (RSV) have substantially reduced infant hospitalizations. However, viral resistance is a concern: one antibody failed clinical trials due to emergence of a resistant strain, and sporadic resistance mutations to the most widely used antibody (nirsevimab) have been identified in breakthrough infections. Here we define how RSV F mutations affect antibody neutralization. We first provide a biophysical model of how the buffering effect of bivalent IgG binding combines with differences in monovalent Fab potency to explain why nirsevimab resistance mutations are more common in subtype B than subtype A RSV strains. We then perform pseudovirus deep mutational scanning to safely measure how nearly all mutations to F affect its cell entry function and neutralization by the IgG and Fab forms of nirsevimab, clesrovimab, and several other key antibodies. We use these measurements to enable real-time surveillance of RSV sequences for antibody resistance, and identify rare strains with sporadic resistance mutations. Overall, our work improves understanding of the mechanisms by which viral mutations impact antibody neutralization, enables monitoring for natural RSV strains resistant to antibodies of public-health importance, and can help guide development of future antibodies with resilience to viral escape.</p><h2 id="interactive-visualizations" tabindex="-1">Interactive visualizations <a class="header-anchor" href="#interactive-visualizations" aria-label="Permalink to &quot;Interactive visualizations&quot;">​</a></h2><p>The results described in this paper can be interactively visualized at <a href="https://dms-vep.org/RSV_Long_F_DMS/" target="_blank" rel="noreferrer">https://dms-vep.org/RSV_Long_F_DMS/</a>; all computer code and data is at <a href="https://github.com/dms-vep/RSV_Long_F_DMS" target="_blank" rel="noreferrer">https://github.com/dms-vep/RSV_Long_F_DMS</a>.</p>',4),o=[s];function r(c,l,d,m,h,p){return a(),t("div",null,o)}const _=e(n,[["render",r]]);export{f as __pageData,_ as default};
